1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	const PROCESSING_FEE = 5;
13	// Base premiums for main (non-component) items. Components such as runes are
14	// priced separately via componentBasePremium and never read from this table.
15	const BASE_PREMIUMS: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	};
21	const FIRST_INSURANCE_MULTIPLIER = 1.1;
22	
23	const COMPONENT_TYPES = ["rune", "moonstone"];
24	const COMPONENT_BASE_PREMIUM = 25;
25	const COMPONENT_BLOCK_SIZE = 3;
26	const COMPONENT_BLOCK_PREMIUM = 60;
27	
28	const isComponent = (item: Item): boolean =>
29	  COMPONENT_TYPES.includes(item.type);
30	
31	// Base premium for `count` alike components: a block premium applies only for
32	// exactly one block's worth (3) of components; otherwise each is priced individually.
33	const componentBasePremium = (count: number): number => {
34	  if (count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_PREMIUM;
35	  return count * COMPONENT_BASE_PREMIUM;
36	};
37	
38	const countByType = (items: Item[]): Map<string, number> => {
39	  const counts = new Map<string, number>();
40	  for (const item of items) {
41	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
42	  }
43	  return counts;
44	};
45	
46	// The block rule is per-type ("alike" = same type), so price each type's count
47	// independently and sum across types.
48	const componentItemsBase = (componentItems: Item[]): number => {
49	  let base = 0;
50	  for (const count of countByType(componentItems).values()) {
51	    base += withFirstInsurance(componentBasePremium(count));
52	  }
53	  return base;
54	};
55	
56	// Every item is treated as first insurance today, so the 10% surcharge is
57	// applied uniformly to each base premium.
58	const withFirstInsurance = (basePremium: number): number =>
59	  basePremium * FIRST_INSURANCE_MULTIPLIER;
60	
61	// Round up in MHPCO's favour, guarding against floating-point noise
62	// (e.g. 197.50000000001 should still round to 198, not 199).
63	const roundUpInMHPCOFavor = (amount: number): number =>
64	  Math.ceil(Number(amount.toFixed(6)));
65	
66	export const quote = (
67	  items: Item[],
68	  customer: Customer,
69	  contractIndex: number,
70	): number => {
71	  const mainItems = items.filter((item) => !isComponent(item));
72	  const componentItems = items.filter((item) => isComponent(item));
73	
74	  const mainBase = mainItems.reduce(
75	    (sum, item) => sum + withFirstInsurance(BASE_PREMIUMS[item.type]),
76	    0,
77	  );
78	  const componentBase = componentItemsBase(componentItems);
79	
80	  return roundUpInMHPCOFavor(mainBase + componentBase + PROCESSING_FEE);
81	};
82	
83	export const claim = (): number => {
84	  return undefined as unknown as number;
85	};
